{
  "name": "Ninja Hands",
  "description": "A Fruit Ninja-style game controlled by hand gestures using your webcam.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react';
import NinjaGame from './components/NinjaGame';

export default function App() {
  return (
    <div className="w-full h-screen bg-slate-900 text-white overflow-hidden">
      <NinjaGame />
    </div>
  );
}

import { FilesetResolver, HandLandmarker } from '@mediapipe/tasks-vision';

export const createHandLandmarker = async () => {
  const vision = await FilesetResolver.forVisionTasks(
    "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.0/wasm"
  );

  const handLandmarker = await HandLandmarker.createFromOptions(vision, {
    baseOptions: {
      modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
      delegate: "GPU"
    },
    runningMode: "VIDEO",
    numHands: 1
  });

  return handLandmarker;
};

import React, { useEffect, useRef, useState } from 'react';
import { HandLandmarker } from '@mediapipe/tasks-vision';
import { createHandLandmarker } from '../utils/handDetection';
import { Loader2, Camera, Play, RotateCcw, AlertCircle } from 'lucide-react';

// --- Types ---

interface Point {
  x: number;
  y: number;
}

interface Fruit {
  id: number;
  x: number;
  y: number;
  vx: number; // Velocity X
  vy: number; // Velocity Y
  emoji: string;
  radius: number;
  sliced: boolean;
  isBomb: boolean;
}

interface Particle {
  id: number;
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number; // 0 to 1
  color: string;
  size: number;
}

// --- Game Constants ---
const GRAVITY = 0.25;
const FRUIT_SPAWN_RATE = 60; // Frames between spawns
const BLADE_LENGTH = 10; // Number of points in the trail
const FRUITS = ['🍎', '🍌', '🍉', '🍊', '🍇', '🍍'];
const BOMB = '💣';
const BOMB_CHANCE = 0.15; // 15% chance to spawn a bomb

const NinjaGame: React.FC = () => {
  // UI State
  const [gameState, setGameState] = useState<'loading' | 'start' | 'playing' | 'gameover'>('loading');
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(60);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  // Refs for Game Loop & Physics (Mutable state without re-renders)
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const requestRef = useRef<number>();
  const landmarkerRef = useRef<HandLandmarker | null>(null);

  // Game Entities Refs
  const fruitsRef = useRef<Fruit[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const bladePathRef = useRef<Point[]>([]);
  const frameCountRef = useRef(0);
  const scoreRef = useRef(0);
  const isGameOverRef = useRef(false);

  // 1. Initialization: Load AI Model and Setup Camera
  useEffect(() => {
    const init = async () => {
      try {
        // Load MediaPipe Hand Landmarker
        landmarkerRef.current = await createHandLandmarker();

        // Setup Webcam
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { width: 1280, height: 720, facingMode: "user" } 
        });

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.addEventListener('loadeddata', () => {
            setGameState('start');
          });
        }
      } catch (err) {
        console.error(err);
        setErrorMessage("Please allow camera access to play.");
      }
    };
    init();

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  // 2. Game Logic Helper Functions

  const spawnFruit = (width: number, height: number) => {
    const isBomb = Math.random() < BOMB_CHANCE;
    const emoji = isBomb ? BOMB : FRUITS[Math.floor(Math.random() * FRUITS.length)];
    const radius = 30;

    // Spawn at bottom, random X
    const x = Math.random() * (width - 100) + 50;
    const y = height + 50;

    // Launch upwards with slight random angle
    const vx = (Math.random() - 0.5) * 8; 
    const vy = -(Math.random() * 8 + 12); // Upward velocity

    fruitsRef.current.push({
      id: Date.now() + Math.random(),
      x, y, vx, vy,
      emoji,
      radius,
      sliced: false,
      isBomb
    });
  };

  const createExplosion = (x: number, y: number, color: string) => {
    for (let i = 0; i < 15; i++) {
      particlesRef.current.push({
        id: Math.random(),
        x, y,
        vx: (Math.random() - 0.5) * 15,
        vy: (Math.random() - 0.5) * 15,
        life: 1.0,
        color,
        size: Math.random() * 5 + 2
      });
    }
  };

  // 3. The Main Game Loop
  const loop = () => {
    if (gameState !== 'playing' && gameState !== 'gameover') return;

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    const video = videoRef.current;
    const landmarker = landmarkerRef.current;

    if (!canvas || !ctx || !video || !landmarker) return;

    // A. Detect Hands
    let handX = -1;
    let handY = -1;

    // Only detect if video has data
    if (video.videoWidth > 0) {
      const results = landmarker.detectForVideo(video, performance.now());
      if (results.landmarks && results.landmarks.length > 0) {
        // Get Index Finger Tip (Landmark 8)
        const hand = results.landmarks[0];
        const indexTip = hand[8];

        // Convert normalized coordinates (0-1) to canvas coordinates
        // Note: x is mirrored for natural feeling
        handX = (1 - indexTip.x) * canvas.width;
        handY = indexTip.y * canvas.height;

        // Update Blade Path
        bladePathRef.current.push({ x: handX, y: handY });
        if (bladePathRef.current.length > BLADE_LENGTH) {
          bladePathRef.current.shift();
        }
      } else {
        // If no hand, shorten path gradually
        if (bladePathRef.current.length > 0) bladePathRef.current.shift();
      }
    }

    // B. Clear & Update Canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // C. Draw Video Feed (Optional: Semi-transparent background)
    ctx.save();
    ctx.globalAlpha = 0.3;
    ctx.translate(canvas.width, 0);
    ctx.scale(-1, 1); // Mirror the video
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    ctx.restore();

    if (isGameOverRef.current) return;

    // D. Update Physics & Draw Fruits
    fruitsRef.current.forEach((fruit, index) => {
      // Apply Gravity
      fruit.vy += GRAVITY;
      fruit.x += fruit.vx;
      fruit.y += fruit.vy;

      // Draw Fruit
      ctx.font = `${fruit.radius * 2}px Arial`;
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText(fruit.emoji, fruit.x, fruit.y);

      // Check Collision with Blade
      if (!fruit.sliced && bladePathRef.current.length >= 2) {
        // Check distance between current finger tip and fruit
        // Simple collision: if tip is inside fruit radius
        // Better collision: Line segment intersection (simplified here for performance)
        const tip = bladePathRef.current[bladePathRef.current.length - 1];
        const prev = bladePathRef.current[bladePathRef.current.length - 2];

        // Calculate distance from point to line segment
        // Or simpler: just check if the blade points are close enough
        const dx = tip.x - fruit.x;
        const dy = tip.y - fruit.y;
        const dist = Math.sqrt(dx * dx + dy * dy);

        // If blade is moving fast enough and hits fruit
        const speed = Math.sqrt(Math.pow(tip.x - prev.x, 2) + Math.pow(tip.y - prev.y, 2));

        if (dist < fruit.radius && speed > 5) {
          if (fruit.isBomb) {
            handleGameOver();
          } else {
            // Slice!
            fruit.sliced = true;
            scoreRef.current += 10;
            setScore(scoreRef.current);
            createExplosion(fruit.x, fruit.y, '#ffff00'); // Yellow splash
            // Remove fruit instantly or play split animation
            fruitsRef.current.splice(index, 1);
          }
        }
      }
    });

    // Remove off-screen fruits
    fruitsRef.current = fruitsRef.current.filter(f => f.y < canvas.height + 100);

    // E. Spawn New Fruits
    frameCountRef.current++;
    if (frameCountRef.current % FRUIT_SPAWN_RATE === 0) {
      spawnFruit(canvas.width, canvas.height);
    }

    // F. Update & Draw Particles
    particlesRef.current.forEach((p, i) => {
      p.x += p.vx;
      p.y += p.vy;
      p.vy += GRAVITY * 0.5; // Lighter gravity for juice
      p.life -= 0.02;

      ctx.fillStyle = p.color;
      ctx.globalAlpha = p.life;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      if (p.life <= 0) particlesRef.current.splice(i, 1);
    });

    // G. Draw Blade Trail
    if (bladePathRef.current.length > 1) {
      ctx.beginPath();
      ctx.strokeStyle = 'cyan';
      ctx.lineWidth = 8;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.shadowBlur = 10;
      ctx.shadowColor = 'cyan';

      // Move to first point
      ctx.moveTo(bladePathRef.current[0].x, bladePathRef.current[0].y);

      // Line to subsequent points
      for (let i = 1; i < bladePathRef.current.length; i++) {
        ctx.lineTo(bladePathRef.current[i].x, bladePathRef.current[i].y);
      }
      ctx.stroke();

      // Reset Shadow
      ctx.shadowBlur = 0;
    }

    requestRef.current = requestAnimationFrame(loop);
  };

  // 4. Game Control Functions
  const startGame = () => {
    setGameState('playing');
    setScore(0);
    setTimeLeft(60);

    // Reset Refs
    scoreRef.current = 0;
    fruitsRef.current = [];
    particlesRef.current = [];
    isGameOverRef.current = false;
    frameCountRef.current = 0;

    // Resize Canvas to Match Window
    if (canvasRef.current) {
      canvasRef.current.width = window.innerWidth;
      canvasRef.current.height = window.innerHeight;
    }

    requestRef.current = requestAnimationFrame(loop);

    // Start Timer
    const timerInterval = setInterval(() => {
      if (isGameOverRef.current) {
        clearInterval(timerInterval);
        return;
      }

      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timerInterval);
          handleGameOver();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  const handleGameOver = () => {
    isGameOverRef.current = true;
    setGameState('gameover');
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
  };

  // Handle Resize
  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);


  return (
    <div className="relative w-full h-full font-sans">
      {/* Hidden Video Element for MediaPipe */}
      <video 
        ref={videoRef} 
        className="hidden" 
        autoPlay 
        playsInline 
        muted
      />

      {/* Game Canvas */}
      <canvas 
        ref={canvasRef} 
        className="block absolute top-0 left-0 w-full h-full cursor-none"
      />

      {/* --- UI OVERLAYS --- */}

      {/* Loading Screen */}
      {gameState === 'loading' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900 bg-opacity-95 z-50">
          {!errorMessage ? (
            <>
              <Loader2 className="w-16 h-16 text-cyan-400 animate-spin mb-4" />
              <h2 className="text-2xl font-bold text-white">Loading Vision AI...</h2>
              <p className="text-slate-400 mt-2">Please grant camera access when prompted.</p>
            </>
          ) : (
            <>
              <AlertCircle className="w-16 h-16 text-red-500 mb-4" />
              <h2 className="text-2xl font-bold text-white">Error</h2>
              <p className="text-red-400 mt-2 max-w-md text-center">{errorMessage}</p>
            </>
          )}
        </div>
      )}

      {/* Start Screen */}
      {gameState === 'start' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-black bg-opacity-80 z-40 backdrop-blur-sm">
          <h1 className="text-6xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-red-500 mb-8 tracking-wider italic">
            NINJA HANDS
          </h1>
          <div className="bg-slate-800 p-8 rounded-2xl border border-slate-700 shadow-2xl text-center max-w-lg">
            <Camera className="w-12 h-12 text-cyan-400 mx-auto mb-4" />
            <h3 className="text-xl font-bold text-white mb-2">How to Play</h3>
            <ul className="text-slate-300 text-left space-y-2 mb-8 text-sm">
              <li>👋 Use your webcam. Step back slightly.</li>
              <li>☝️ Hold up your <strong>index finger</strong>. It's your blade.</li>
              <li>🍎 Slice fruits to gain points.</li>
              <li>💣 Avoid the bombs!</li>
            </ul>
            <button 
              onClick={startGame}
              className="group relative px-8 py-4 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-full text-white font-bold text-xl shadow-lg hover:shadow-cyan-500/50 transition-all transform hover:scale-105"
            >
              <div className="flex items-center gap-2">
                <Play className="fill-current" />
                START GAME
              </div>
            </button>
          </div>
        </div>
      )}

      {/* HUD (Heads Up Display) */}
      {gameState === 'playing' && (
        <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none z-30">
          <div className="flex flex-col">
            <span className="text-yellow-400 font-black text-4xl drop-shadow-md">
              {score}
            </span>
            <span className="text-slate-400 text-sm font-bold uppercase tracking-widest">Score</span>
          </div>

          <div className="flex flex-col items-end">
             <span className={`font-black text-4xl drop-shadow-md ${timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-white'}`}>
              {timeLeft}
            </span>
            <span className="text-slate-400 text-sm font-bold uppercase tracking-widest">Time</span>
          </div>
        </div>
      )}

      {/* Game Over Screen */}
      {gameState === 'gameover' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-black bg-opacity-90 z-50 animate-in fade-in zoom-in duration-300">
          <h2 className="text-5xl font-black text-white mb-2">GAME OVER</h2>
          <p className="text-2xl text-slate-300 mb-8">Final Score: <span className="text-yellow-400 font-bold">{score}</span></p>

          <button 
            onClick={startGame}
            className="flex items-center gap-3 px-8 py-4 bg-white text-black rounded-full font-bold text-xl hover:bg-slate-200 transition-colors shadow-[0_0_20px_rgba(255,255,255,0.3)]"
          >
            <RotateCcw className="w-6 h-6" />
            PLAY AGAIN
          </button>
        </div>
      )}
    </div>
  );
};

export default NinjaGame;

import { FilesetResolver, HandLandmarker } from '@mediapipe/tasks-vision';

export const createHandLandmarker = async () => {
  const vision = await FilesetResolver.forVisionTasks(
    "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.3/wasm"
  );

  const handLandmarker = await HandLandmarker.createFromOptions(vision, {
    baseOptions: {
      modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
      delegate: "GPU"
    },
    runningMode: "VIDEO",
    numHands: 1
  });

  return handLandmarker;
};

import React, { useEffect, useRef, useState } from 'react';
import { HandLandmarker } from '@mediapipe/tasks-vision';
import { createHandLandmarker } from '../utils/handDetection';
import { Loader2, Camera, Play, RotateCcw, AlertCircle } from 'lucide-react';

// --- Types ---

interface Point {
  x: number;
  y: number;
}

interface Fruit {
  id: number;
  x: number;
  y: number;
  vx: number; // Velocity X
  vy: number; // Velocity Y
  emoji: string;
  radius: number;
  sliced: boolean;
  isBomb: boolean;
}

interface Particle {
  id: number;
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number; // 0 to 1
  color: string;
  size: number;
}

// --- Game Constants ---
const GRAVITY = 0.25;
const FRUIT_SPAWN_RATE = 60; // Frames between spawns
const BLADE_LENGTH = 10; // Number of points in the trail
const FRUITS = ['🍎', '🍌', '🍉', '🍊', '🍇', '🍍'];
const BOMB = '💣';
const BOMB_CHANCE = 0.15; // 15% chance to spawn a bomb

const NinjaGame: React.FC = () => {
  // UI State
  const [gameState, setGameState] = useState<'loading' | 'start' | 'playing' | 'gameover'>('loading');
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(60);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  // Refs for Game Loop & Physics (Mutable state without re-renders)
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const requestRef = useRef<number>();
  const landmarkerRef = useRef<HandLandmarker | null>(null);

  // Game State Ref (Crucial for avoiding stale closures in the loop)
  const gameStateRef = useRef<'loading' | 'start' | 'playing' | 'gameover'>('loading');

  // Game Entities Refs
  const fruitsRef = useRef<Fruit[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const bladePathRef = useRef<Point[]>([]);
  const frameCountRef = useRef(0);
  const scoreRef = useRef(0);

  // Sync gameState state with ref
  useEffect(() => {
    gameStateRef.current = gameState;
  }, [gameState]);

  // 1. Initialization: Load AI Model and Setup Camera
  useEffect(() => {
    const init = async () => {
      try {
        // Load MediaPipe Hand Landmarker
        landmarkerRef.current = await createHandLandmarker();

        // Setup Webcam
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { width: 1280, height: 720, facingMode: "user" } 
        });

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.addEventListener('loadeddata', () => {
            setGameState('start');
          });
        }
      } catch (err) {
        console.error(err);
        setErrorMessage("Please allow camera access to play.");
      }
    };
    init();

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  // 2. Game Logic Helper Functions

  const spawnFruit = (width: number, height: number) => {
    const isBomb = Math.random() < BOMB_CHANCE;
    const emoji = isBomb ? BOMB : FRUITS[Math.floor(Math.random() * FRUITS.length)];
    const radius = 30;

    // Spawn at bottom, random X
    const x = Math.random() * (width - 100) + 50;
    const y = height + 50;

    // Launch upwards with slight random angle
    const vx = (Math.random() - 0.5) * 8; 
    const vy = -(Math.random() * 8 + 12); // Upward velocity

    fruitsRef.current.push({
      id: Date.now() + Math.random(),
      x, y, vx, vy,
      emoji,
      radius,
      sliced: false,
      isBomb
    });
  };

  const createExplosion = (x: number, y: number, color: string) => {
    for (let i = 0; i < 15; i++) {
      particlesRef.current.push({
        id: Math.random(),
        x, y,
        vx: (Math.random() - 0.5) * 15,
        vy: (Math.random() - 0.5) * 15,
        life: 1.0,
        color,
        size: Math.random() * 5 + 2
      });
    }
  };

  // 3. The Main Game Loop
  const loop = () => {
    // Check against Ref to ensure we have the latest state inside the loop
    if (gameStateRef.current !== 'playing' && gameStateRef.current !== 'gameover') return;

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    const video = videoRef.current;
    const landmarker = landmarkerRef.current;

    if (!canvas || !ctx || !video || !landmarker) return;

    // A. Detect Hands
    let handX = -1;
    let handY = -1;

    // Only detect if video has data
    if (video.readyState >= 2) {
      const results = landmarker.detectForVideo(video, performance.now());
      if (results.landmarks && results.landmarks.length > 0) {
        // Get Index Finger Tip (Landmark 8)
        const hand = results.landmarks[0];
        const indexTip = hand[8];

        // Convert normalized coordinates (0-1) to canvas coordinates
        // Note: x is mirrored for natural feeling
        handX = (1 - indexTip.x) * canvas.width;
        handY = indexTip.y * canvas.height;

        // Update Blade Path
        bladePathRef.current.push({ x: handX, y: handY });
        if (bladePathRef.current.length > BLADE_LENGTH) {
          bladePathRef.current.shift();
        }
      } else {
        // If no hand, shorten path gradually
        if (bladePathRef.current.length > 0) bladePathRef.current.shift();
      }
    }

    // B. Clear & Update Canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // C. Draw Video Feed (Optional: Semi-transparent background)
    ctx.save();
    ctx.globalAlpha = 0.3;
    ctx.translate(canvas.width, 0);
    ctx.scale(-1, 1); // Mirror the video
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    ctx.restore();

    if (gameStateRef.current === 'gameover') {
       // Just keep drawing the last frame of background, but stop updates
       return; 
    }

    // D. Update Physics & Draw Fruits
    fruitsRef.current.forEach((fruit, index) => {
      // Apply Gravity
      fruit.vy += GRAVITY;
      fruit.x += fruit.vx;
      fruit.y += fruit.vy;

      // Draw Fruit
      ctx.font = `${fruit.radius * 2}px Arial`;
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText(fruit.emoji, fruit.x, fruit.y);

      // Check Collision with Blade
      if (!fruit.sliced && bladePathRef.current.length >= 2) {
        const tip = bladePathRef.current[bladePathRef.current.length - 1];
        const prev = bladePathRef.current[bladePathRef.current.length - 2];

        const dx = tip.x - fruit.x;
        const dy = tip.y - fruit.y;
        const dist = Math.sqrt(dx * dx + dy * dy);

        // Calculate speed of finger
        const speed = Math.sqrt(Math.pow(tip.x - prev.x, 2) + Math.pow(tip.y - prev.y, 2));

        // Hit detection
        if (dist < fruit.radius && speed > 5) {
          if (fruit.isBomb) {
            handleGameOver();
          } else {
            // Slice!
            fruit.sliced = true;
            scoreRef.current += 10;
            setScore(scoreRef.current);
            createExplosion(fruit.x, fruit.y, '#ffff00'); // Yellow splash
            // Remove fruit instantly
            fruitsRef.current.splice(index, 1);
          }
        }
      }
    });

    // Remove off-screen fruits
    fruitsRef.current = fruitsRef.current.filter(f => f.y < canvas.height + 100);

    // E. Spawn New Fruits
    frameCountRef.current++;
    if (frameCountRef.current % FRUIT_SPAWN_RATE === 0) {
      spawnFruit(canvas.width, canvas.height);
    }

    // F. Update & Draw Particles
    particlesRef.current.forEach((p, i) => {
      p.x += p.vx;
      p.y += p.vy;
      p.vy += GRAVITY * 0.5; // Lighter gravity for juice
      p.life -= 0.02;

      ctx.fillStyle = p.color;
      ctx.globalAlpha = p.life;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      if (p.life <= 0) particlesRef.current.splice(i, 1);
    });

    // G. Draw Blade Trail
    if (bladePathRef.current.length > 1) {
      ctx.beginPath();
      ctx.strokeStyle = 'cyan';
      ctx.lineWidth = 8;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.shadowBlur = 10;
      ctx.shadowColor = 'cyan';

      ctx.moveTo(bladePathRef.current[0].x, bladePathRef.current[0].y);
      for (let i = 1; i < bladePathRef.current.length; i++) {
        ctx.lineTo(bladePathRef.current[i].x, bladePathRef.current[i].y);
      }
      ctx.stroke();
      ctx.shadowBlur = 0;
    }

    requestRef.current = requestAnimationFrame(loop);
  };

  // 4. Game Control Functions
  const startGame = () => {
    // IMPORTANT: Set ref immediately so loop sees it
    gameStateRef.current = 'playing';
    setGameState('playing');

    setScore(0);
    setTimeLeft(60);

    // Reset Refs
    scoreRef.current = 0;
    fruitsRef.current = [];
    particlesRef.current = [];
    frameCountRef.current = 0;
    bladePathRef.current = [];

    // Resize Canvas to Match Window
    if (canvasRef.current) {
      canvasRef.current.width = window.innerWidth;
      canvasRef.current.height = window.innerHeight;
    }

    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = requestAnimationFrame(loop);

    // Start Timer
    const timerInterval = setInterval(() => {
      // Check ref, not state
      if (gameStateRef.current === 'gameover') {
        clearInterval(timerInterval);
        return;
      }

      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timerInterval);
          handleGameOver();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  const handleGameOver = () => {
    gameStateRef.current = 'gameover';
    setGameState('gameover');
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
  };

  // Handle Resize
  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);


  return (
    <div className="relative w-full h-full font-sans bg-slate-900">
      {/* 
        Video MUST be rendered for MediaPipe to work. 
        We use opacity-0 and z-index -10 so it's technically "visible" to the DOM/JS 
