  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Game State Ref (Crucial for avoiding stale closures in the loop)
  const gameStateRef = useRef<'loading' | 'start' | 'playing' | 'gameover'>('loading');

  // Game Entities Refs
  const fruitsRef = useRef<Fruit[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const bladePathRef = useRef<Point[]>([]);
  const frameCountRef = useRef(0);
  const scoreRef = useRef(0);

  // Sync gameState state with ref
  useEffect(() => {
    gameStateRef.current = gameState;
  }, [gameState]);

  // 1. Initialization: Load AI Model and Setup Camera
  useEffect(() => {
    const init = async () => {
      try {
        // Load MediaPipe Hand Landmarker
        landmarkerRef.current = await createHandLandmarker();

        // Setup Webcam
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { width: 1280, height: 720, facingMode: "user" } 
        });

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.addEventListener('loadeddata', () => {
            setGameState('start');
          });
        }
      } catch (err) {
        console.error(err);
        setErrorMessage("Please allow camera access to play.");
      }
    };
    init();

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  // 2. Game Logic Helper Functions

  const spawnFruit = (width: number, height: number) => {
    const isBomb = Math.random() < BOMB_CHANCE;
    const emoji = isBomb ? BOMB : FRUITS[Math.floor(Math.random() * FRUITS.length)];
    const radius = 30;

    // Spawn at bottom, random X
    const x = Math.random() * (width - 100) + 50;
    const y = height + 50;

    // Launch upwards with slight random angle
    const vx = (Math.random() - 0.5) * 8; 
    const vy = -(Math.random() * 8 + 12); // Upward velocity

    fruitsRef.current.push({
      id: Date.now() + Math.random(),
      x, y, vx, vy,
      emoji,
      radius,
      sliced: false,
      isBomb
    });
  };

  const createExplosion = (x: number, y: number, color: string) => {
    for (let i = 0; i < 15; i++) {
      particlesRef.current.push({
        id: Math.random(),
        x, y,
        vx: (Math.random() - 0.5) * 15,
        vy: (Math.random() - 0.5) * 15,
        life: 1.0,
        color,
        size: Math.random() * 5 + 2
      });
    }
  };

  // 3. The Main Game Loop
  const loop = () => {
    // Check against Ref to ensure we have the latest state inside the loop
    if (gameStateRef.current !== 'playing' && gameStateRef.current !== 'gameover') return;

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    const video = videoRef.current;
    const landmarker = landmarkerRef.current;

    if (!canvas || !ctx || !video || !landmarker) return;

    // A. Detect Hands
    let handX = -1;
    let handY = -1;

    // Only detect if video has data
    if (video.readyState >= 2) {
      const results = landmarker.detectForVideo(video, performance.now());
      if (results.landmarks && results.landmarks.length > 0) {
        // Get Index Finger Tip (Landmark 8)
        const hand = results.landmarks[0];
        const indexTip = hand[8];

        // Convert normalized coordinates (0-1) to canvas coordinates
        // Note: x is mirrored for natural feeling
        handX = (1 - indexTip.x) * canvas.width;
        handY = indexTip.y * canvas.height;

        // Update Blade Path
        bladePathRef.current.push({ x: handX, y: handY });
        if (bladePathRef.current.length > BLADE_LENGTH) {
          bladePathRef.current.shift();
        }
      } else {
        // If no hand, shorten path gradually
        if (bladePathRef.current.length > 0) bladePathRef.current.shift();
      }
    }

    // B. Clear & Update Canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // C. Draw Video Feed (Optional: Semi-transparent background)
    ctx.save();
    ctx.globalAlpha = 0.3;
    ctx.translate(canvas.width, 0);
    ctx.scale(-1, 1); // Mirror the video
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    ctx.restore();

    if (gameStateRef.current === 'gameover') {
       // Just keep drawing the last frame of background, but stop updates
       return; 
    }

    // D. Update Physics & Draw Fruits
    // Use reverse loop to safely splice items
    for (let i = fruitsRef.current.length - 1; i >= 0; i--) {
      const fruit = fruitsRef.current[i];

      // Apply Gravity
      fruit.vy += GRAVITY;
      fruit.x += fruit.vx;
      fruit.y += fruit.vy;

      // Draw Fruit
      ctx.font = `${fruit.radius * 2}px Arial`;
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText(fruit.emoji, fruit.x, fruit.y);

      // Remove if off screen
      if (fruit.y > canvas.height + 100) {
        fruitsRef.current.splice(i, 1);
        continue;
      }

      // Check Collision with Blade
      if (!fruit.sliced && bladePathRef.current.length >= 2) {
        const tip = bladePathRef.current[bladePathRef.current.length - 1];
        const prev = bladePathRef.current[bladePathRef.current.length - 2];

        const dx = tip.x - fruit.x;
        const dy = tip.y - fruit.y;
        const dist = Math.sqrt(dx * dx + dy * dy);

        // Calculate speed of finger
        const speed = Math.sqrt(Math.pow(tip.x - prev.x, 2) + Math.pow(tip.y - prev.y, 2));

        // Hit detection
        if (dist < fruit.radius && speed > 5) {
          if (fruit.isBomb) {
            handleGameOver();
          } else {
            // Slice!
            scoreRef.current += 10;
            setScore(scoreRef.current);
            createExplosion(fruit.x, fruit.y, '#ffff00'); // Yellow splash
            // Remove fruit instantly
            fruitsRef.current.splice(i, 1);
          }
        }
      }
    }

    // E. Spawn New Fruits
    frameCountRef.current++;
    if (frameCountRef.current % FRUIT_SPAWN_RATE === 0) {
      spawnFruit(canvas.width, canvas.height);
    }

    // F. Update & Draw Particles
    // Iterate backwards to allow removal
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
      const p = particlesRef.current[i];
      p.x += p.vx;
      p.y += p.vy;
      p.vy += GRAVITY * 0.5;
      p.life -= 0.02;

      if (p.life <= 0) {
        particlesRef.current.splice(i, 1);
      } else {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1.0;
      }
    }

    // G. Draw Blade Trail
    if (bladePathRef.current.length > 1) {
      ctx.beginPath();
      ctx.strokeStyle = 'cyan';
      ctx.lineWidth = 8;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.shadowBlur = 10;
      ctx.shadowColor = 'cyan';

      ctx.moveTo(bladePathRef.current[0].x, bladePathRef.current[0].y);
      for (let i = 1; i < bladePathRef.current.length; i++) {
        ctx.lineTo(bladePathRef.current[i].x, bladePathRef.current[i].y);
      }
      ctx.stroke();
      ctx.shadowBlur = 0;
    }

    requestRef.current = requestAnimationFrame(loop);
  };

  // 4. Game Control Functions
  const startGame = () => {
    // IMPORTANT: Set ref immediately so loop sees it
    gameStateRef.current = 'playing';
    setGameState('playing');

    setScore(0);
    setTimeLeft(60);

    // Reset Refs
    scoreRef.current = 0;
    fruitsRef.current = [];
    particlesRef.current = [];
    frameCountRef.current = 0;
    bladePathRef.current = [];

    // Resize Canvas to Match Window
    if (canvasRef.current) {
      canvasRef.current.width = window.innerWidth;
      canvasRef.current.height = window.innerHeight;
    }

    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = requestAnimationFrame(loop);

    // Clear any existing timer
    if (timerRef.current) clearInterval(timerRef.current);

    // Start Timer
    timerRef.current = setInterval(() => {
      // Check ref, not state
      if (gameStateRef.current === 'gameover') {
        if (timerRef.current) clearInterval(timerRef.current);
        return;
      }

      setTimeLeft(prev => {
        if (prev <= 1) {
          if (timerRef.current) clearInterval(timerRef.current);
          handleGameOver();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  const handleGameOver = () => {
    gameStateRef.current = 'gameover';
    setGameState('gameover');
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    if (timerRef.current) clearInterval(timerRef.current);
  };

  // Handle Resize
  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);


  return (
    <div className="relative w-full h-full font-sans bg-slate-900">
      {/* 
        Video MUST be rendered for MediaPipe to work. 
        We use opacity-0 and z-index -10 so it's technically "visible" to the DOM/JS 
        but invisible to the user, allowing correct detection. 
      */}
      <video 
        ref={videoRef} 
        className="absolute top-0 left-0 w-full h-full object-cover opacity-0 pointer-events-none -z-10"
        autoPlay 
        playsInline 
        muted
      />

      {/* Game Canvas */}
      <canvas 
        ref={canvasRef} 
        className="block absolute top-0 left-0 w-full h-full cursor-none"
      />

      {/* --- UI OVERLAYS --- */}

      {/* Loading Screen */}
      {gameState === 'loading' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900 z-50">
          {!errorMessage ? (
            <>
              <Loader2 className="w-16 h-16 text-cyan-400 animate-spin mb-4" />
              <h2 className="text-2xl font-bold text-white">Loading Vision AI...</h2>
              <p className="text-slate-400 mt-2">Please grant camera access when prompted.</p>
            </>
          ) : (
            <>
              <AlertCircle className="w-16 h-16 text-red-500 mb-4" />
              <h2 className="text-2xl font-bold text-white">Error</h2>
              <p className="text-red-400 mt-2 max-w-md text-center">{errorMessage}</p>
            </>
          )}
        </div>
      )}

      {/* Start Screen */}
      {gameState === 'start' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-black bg-opacity-80 z-40 backdrop-blur-sm">
          <h1 className="text-6xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-red-500 mb-8 tracking-wider italic">
            NINJA HANDS
          </h1>
          <div className="bg-slate-800 p-8 rounded-2xl border border-slate-700 shadow-2xl text-center max-w-lg">
            <Camera className="w-12 h-12 text-cyan-400 mx-auto mb-4" />
            <h3 className="text-xl font-bold text-white mb-2">How to Play</h3>
            <ul className="text-slate-300 text-left space-y-2 mb-8 text-sm">
              <li>👋 Use your webcam. Step back slightly.</li>
              <li>☝️ Hold up your <strong>index finger</strong>. It's your blade.</li>
              <li>🍎 Slice fruits to gain points.</li>
              <li>💣 Avoid the bombs!</li>
            </ul>
            <button 
              onClick={startGame}
              className="group relative px-8 py-4 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-full text-white font-bold text-xl shadow-lg hover:shadow-cyan-500/50 transition-all transform hover:scale-105"
            >
              <div className="flex items-center gap-2">
                <Play className="fill-current" />
                START GAME
              </div>
            </button>
          </div>
        </div>
      )}

      {/* HUD (Heads Up Display) */}
      {gameState === 'playing' && (
        <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none z-30">
          <div className="flex flex-col">
            <span className="text-yellow-400 font-black text-4xl drop-shadow-md">
              {score}
            </span>
            <span className="text-slate-400 text-sm font-bold uppercase tracking-widest">Score</span>
          </div>

          <div className="flex flex-col items-end">
             <span className={`font-black text-4xl drop-shadow-md ${timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-white'}`}>
              {timeLeft}
            </span>
            <span className="text-slate-400 text-sm font-bold uppercase tracking-widest">Time</span>
          </div>
        </div>
      )}

      {/* Game Over Screen */}
      {gameState === 'gameover' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-black bg-opacity-90 z-50 animate-in fade-in zoom-in duration-300">
          <h2 className="text-5xl font-black text-white mb-2">GAME OVER</h2>
          <p className="text-2xl text-slate-300 mb-8">Final Score: <span className="text-yellow-400 font-bold">{score}</span></p>

          <button 
            onClick={startGame}
            className="flex items-center gap-3 px-8 py-4 bg-white text-black rounded-full font-bold text-xl hover:bg-slate-200 transition-colors shadow-[0_0_20px_rgba(255,255,255,0.3)]"
          >
            <RotateCcw className="w-6 h-6" />
            PLAY AGAIN
          </button>
        </div>
      )}
    </div>
  );
};

export default NinjaGame;

{
  "name": "Neon Blade",
  "description": "A rhythm action game. Slash the beats with your hands! Blue for Right, Red for Left.",
  "requestFramePermissions": [
    "camera"
  ]
}

import { FilesetResolver, HandLandmarker } from '@mediapipe/tasks-vision';

export const createHandLandmarker = async () => {
  const vision = await FilesetResolver.forVisionTasks(
    "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.3/wasm"
  );

  const handLandmarker = await HandLandmarker.createFromOptions(vision, {
    baseOptions: {
      modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
      delegate: "GPU"
    },
    runningMode: "VIDEO",
    numHands: 2
  });

  return handLandmarker;
};

import React, { useEffect, useRef, useState } from 'react';
import { HandLandmarker } from '@mediapipe/tasks-vision';
import { createHandLandmarker } from '../utils/handDetection';
import { Loader2, Zap, Play, RotateCcw, Volume2, ShieldAlert } from 'lucide-react';

// --- Types ---

interface Point {
  x: number;
  y: number;
}

interface Cube {
  id: number;
  laneX: number; // -1 (left) to 1 (right)
  laneY: number; // -1 (up) to 1 (down)
  z: number;     // Depth: starts high, moves to 0
  color: 'red' | 'blue';
  hit: boolean;
}

interface Particle {
  id: number;
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

// --- Game Constants ---
const Z_START = 1000;
const Z_HIT = 100; // The "plane" where player slices
const SPEED = 15;
const FOCAL_LENGTH = 600;

// Colors
const COLOR_RED = '#ff0055'; // Left Hand
const COLOR_BLUE = '#00aaff'; // Right Hand

const RhythmGame: React.FC = () => {
  // UI State
  const [gameState, setGameState] = useState<'loading' | 'start' | 'playing' | 'gameover'>('loading');
  const [score, setScore] = useState(0);
  const [combo, setCombo] = useState(0);
  const [health, setHealth] = useState(100);

  // Refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const requestRef = useRef<number>();
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);

  // Game Logic Refs (Mutable)
  const cubesRef = useRef<Cube[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const frameCountRef = useRef(0);
  const handTrailsRef = useRef<{ left: Point[], right: Point[] }>({ left: [], right: [] });
  const gameStateRef = useRef(gameState);

  // Sync ref
  useEffect(() => {
    gameStateRef.current = gameState;
  }, [gameState]);

  // 1. Initialize System
  useEffect(() => {
    const init = async () => {
      try {
        landmarkerRef.current = await createHandLandmarker();
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { width: 1280, height: 720, facingMode: "user" } 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.addEventListener('loadeddata', () => setGameState('start'));
        }
      } catch (err) {
        console.error(err);
      }
    };
    init();

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (audioCtxRef.current) audioCtxRef.current.close();
    };
  }, []);

  // 2. Audio Engine (Synthesizer)
  // We synthesize a beat so we don't need external assets
  const playSound = (type: 'kick' | 'snare' | 'hihat' | 'miss' | 'hit') => {
    if (!audioCtxRef.current) return;
    const ctx = audioCtxRef.current;
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    if (type === 'hit') {
      osc.type = 'sine';
      osc.frequency.setValueAtTime(800, t);
      osc.frequency.exponentialRampToValueAtTime(0.01, t + 0.1);
      gain.gain.setValueAtTime(0.3, t);
      gain.gain.exponentialRampToValueAtTime(0.01, t + 0.1);
      osc.start(t);
      osc.stop(t + 0.1);
    } else if (type === 'kick') {
      osc.frequency.setValueAtTime(150, t);
      osc.frequency.exponentialRampToValueAtTime(0.01, t + 0.5);
      gain.gain.setValueAtTime(0.8, t);
      gain.gain.exponentialRampToValueAtTime(0.01, t + 0.5);
      osc.start(t);
      osc.stop(t + 0.5);
    } else if (type === 'snare') {
      osc.type = 'triangle';
      gain.gain.setValueAtTime(0.5, t);
      gain.gain.exponentialRampToValueAtTime(0.01, t + 0.2);
      osc.start(t);
      osc.stop(t + 0.2);
    } else if (type === 'miss') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(100, t);
      osc.frequency.linearRampToValueAtTime(50, t + 0.3);
      gain.gain.setValueAtTime(0.5, t);
      gain.gain.linearRampToValueAtTime(0.01, t + 0.3);
      osc.start(t);
      osc.stop(t + 0.3);
    }
  };

  // 3. Helper: 3D to 2D Projection
  const project = (x: number, y: number, z: number, width: number, height: number) => {
    // Standard perspective projection
    const scale = FOCAL_LENGTH / (FOCAL_LENGTH + z);
    const x2d = (x * width) * scale + (width / 2);
    const y2d = (y * height) * scale + (height / 2);
    return { x: x2d, y: y2d, scale };
  };

  const spawnCube = () => {
    // Random position in 2x2 grid
    // lanes: -0.5 (left/up) and 0.5 (right/down) give nice spacing
    const laneX = Math.random() > 0.5 ? 0.3 : -0.3;
    const laneY = Math.random() > 0.5 ? 0.2 : -0.2;

    // Color often matches side (Left=Red, Right=Blue) but sometimes crosses
    let color: 'red' | 'blue' = laneX < 0 ? 'red' : 'blue';
    if (Math.random() < 0.2) color = color === 'red' ? 'blue' : 'red'; // 20% crossover

    cubesRef.current.push({
      id: Date.now() + Math.random(),
      laneX,
      laneY,
      z: Z_START,
      color,
      hit: false
    });
  };

  const createParticles = (x: number, y: number, color: string) => {
    for (let i = 0; i < 10; i++) {
      particlesRef.current.push({
        id: Math.random(),
        x, y,
        vx: (Math.random() - 0.5) * 20,
        vy: (Math.random() - 0.5) * 20,
        life: 1.0,
        color,
        size: Math.random() * 10 + 5
      });
    }
  };

  // 4. Game Loop
  const loop = () => {
    if (gameStateRef.current !== 'playing' && gameStateRef.current !== 'gameover') return;

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    const video = videoRef.current;
    const landmarker = landmarkerRef.current;

    if (!canvas || !ctx || !video || !landmarker) return;

    // A. Hand Tracking
    let leftHand: Point | null = null;
    let rightHand: Point | null = null;

    if (video.readyState >= 2) {
      const results = landmarker.detectForVideo(video, performance.now());

      // Process Hands
      if (results.landmarks) {
        results.landmarks.forEach((landmarks, index) => {
          const handedness = results.handedness[index][0]; // "Left" or "Right"
          const indexTip = landmarks[8];

          // Map Coordinates (Mirror X)
          const x = (1 - indexTip.x) * canvas.width;
          const y = indexTip.y * canvas.height;

          // MediaPipe "Left" is the person's Left Hand (which appears on Left side if mirrored)
          // We assign RED to Left Hand, BLUE to Right Hand
          if (handedness.categoryName === 'Left') {
            rightHand = { x, y }; // MediaPipe "Left" is usually user's left, but video is mirrored.
                                  // Let's stick to: visual Left = Red, visual Right = Blue.
                                  // Handedness logic can be tricky with mirroring. 
                                  // Let's assume visual left side is controlled by one hand.
                                  // Actually, let's just use the handedness strictly.
          } else {
            leftHand = { x, y };
          }
        });
      }
    }

    // Fix Hand Assignment for Mirrored Video
    // In mirrored mode: User raises Left hand -> Shows on Left side of screen -> MP calls it "Left".
    // We want Left Screen Side = Red.
    // So MP "Left" = Red Saber. MP "Right" = Blue Saber.
    // NOTE: The variables above might be named counter-intuitively depending on camera driver.
    // Let's simplify: 
    // Hand A is the one with x < width/2 (approx), Hand B is x > width/2
    // But Beat Saber requires crossing. 
    // Let's stick to MP categories: Left Hand = Red, Right Hand = Blue.

    // Update Trails
    if (leftHand) {
      handTrailsRef.current.left.push(leftHand);
      if (handTrailsRef.current.left.length > 10) handTrailsRef.current.left.shift();
    }
    if (rightHand) {
      handTrailsRef.current.right.push(rightHand);
      if (handTrailsRef.current.right.length > 10) handTrailsRef.current.right.shift();
    }

    // B. Clear & Draw Background
    ctx.fillStyle = '#111';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Draw Video (Faint)
    ctx.save();
    ctx.globalAlpha = 0.2;
    ctx.translate(canvas.width, 0);
    ctx.scale(-1, 1);
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    ctx.restore();

    // Draw Perspective Grid (The "Tunnel")
    ctx.strokeStyle = '#333';
    ctx.lineWidth = 2;
    ctx.beginPath();
    // Floor lines
    for (let i = -2; i <= 2; i++) {
        const start = project(i * 0.5, 0.5, 0, canvas.width, canvas.height);
        const end = project(i * 2, 0.5, Z_START, canvas.width, canvas.height);
        ctx.moveTo(start.x, start.y);
        ctx.lineTo(end.x, end.y);
    }
    ctx.stroke();

    if (gameStateRef.current === 'gameover') {
      return; // Stop updating physics
    }

    // C. Music Sequencing (Simple Beat)
    frameCountRef.current++;
    // 120 BPM approx at 60fps = beat every 30 frames
    if (frameCountRef.current % 30 === 0) {
      spawnCube();
      // Simple Rhythm Pattern: Kick, Hat, Snare, Hat
      const beat = (frameCountRef.current / 30) % 4;
      if (beat === 0) playSound('kick');
      else if (beat === 2) playSound('snare');
      else playSound('kick'); // Constant drive
    }

    // D. Update & Draw Cubes
    for (let i = cubesRef.current.length - 1; i >= 0; i--) {
      const cube = cubesRef.current[i];
      cube.z -= SPEED;

      // Projection
      const proj = project(cube.laneX, cube.laneY, cube.z, canvas.width, canvas.height);
      const size = 60 * proj.scale; // Base size * perspective scale

      // Draw Cube
      ctx.fillStyle = cube.color === 'red' ? COLOR_RED : COLOR_BLUE;
      ctx.globalAlpha = Math.min(1, 1000 / cube.z); // Fade in

      // Draw a glowing box
      ctx.shadowBlur = 20;
      ctx.shadowColor = cube.color === 'red' ? COLOR_RED : COLOR_BLUE;
      ctx.fillRect(proj.x - size/2, proj.y - size/2, size, size);

      // Inner white box (the "arrow" placeholder)
      ctx.fillStyle = 'white';
      ctx.fillRect(proj.x - size/4, proj.y - size/4, size/2, size/2);

      ctx.shadowBlur = 0;
      ctx.globalAlpha = 1.0;

      // Collision Detection
      // We check if cube is near the "Hit Plane" (Z ~= 0 to 200)
      if (!cube.hit && cube.z < 200 && cube.z > -50) {
        const targetHand = cube.color === 'red' ? handTrailsRef.current.left : handTrailsRef.current.right;

        // Check if the specific hand is close to the projected cube center
        if (targetHand.length > 0) {
          const handPos = targetHand[targetHand.length - 1]; // Latest position
          const dx = handPos.x - proj.x;
          const dy = handPos.y - proj.y;
          const dist = Math.sqrt(dx*dx + dy*dy);

          // Hit!
          if (dist < size * 1.5) { // Forgiving hit box
            cube.hit = true;
            playSound('hit');
            createParticles(proj.x, proj.y, cube.color === 'red' ? COLOR_RED : COLOR_BLUE);
            setScore(prev => prev + 100);
            setCombo(prev => prev + 1);
            cubesRef.current.splice(i, 1);
            continue;
          }
        }
      }

      // Miss Logic (Passed the camera)
      if (cube.z < -200) {
        if (!cube.hit) {
            playSound('miss');
            setCombo(0);
            setHealth(prev => {
                const newHealth = prev - 10;
                if (newHealth <= 0) handleGameOver();
                return newHealth;
            });
        }
        cubesRef.current.splice(i, 1);
      }
    }

    // E. Draw Sabers (Trails)
    const drawTrail = (points: Point[], color: string) => {
      if (points.length < 2) return;
      ctx.beginPath();
      ctx.strokeStyle = color;
      ctx.lineWidth = 15;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.shadowBlur = 20;
      ctx.shadowColor = color;
      ctx.moveTo(points[0].x, points[0].y);
      for (let i = 1; i < points.length; i++) {
        ctx.lineTo(points[i].x, points[i].y);
      }
      ctx.stroke();
      ctx.shadowBlur = 0;
    };

    // Draw Left (Red) Hand - actually detected as Right by MP often due to mirroring, 
    // but we mapped MP Left -> Red earlier.
    if (handTrailsRef.current.left.length > 0) drawTrail(handTrailsRef.current.left, COLOR_RED);
    if (handTrailsRef.current.right.length > 0) drawTrail(handTrailsRef.current.right, COLOR_BLUE);


    // F. Draw Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
      const p = particlesRef.current[i];
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 0.05;
      if (p.life <= 0) {
        particlesRef.current.splice(i, 1);
      } else {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI*2);
        ctx.fill();
        ctx.globalAlpha = 1;
      }
    }

    requestRef.current = requestAnimationFrame(loop);
  };

  // 5. State Management
  const startGame = async () => {
    // Init Audio Context on user interaction (required by browsers)
    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioCtxRef.current?.state === 'suspended') {
      await audioCtxRef.current.resume();
    }

    setGameState('playing');
    setScore(0);
    setCombo(0);
    setHealth(100);

    cubesRef.current = [];
    particlesRef.current = [];
    handTrailsRef.current = { left: [], right: [] };
    frameCountRef.current = 0;

    if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
    }

    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = requestAnimationFrame(loop);
  };

  const handleGameOver = () => {
    setGameState('gameover');
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
  };

  // Resize handler
  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return (
    <div className="relative w-full h-full font-sans bg-black overflow-hidden select-none">
      {/* Hidden Video for CV */}
      <video 
        ref={videoRef} 
        className="absolute top-0 left-0 w-full h-full object-cover opacity-0 pointer-events-none -z-10"
        autoPlay 
        playsInline 
        muted
      />

      <canvas ref={canvasRef} className="block absolute top-0 left-0 w-full h-full" />

      {/* --- UI --- */}

      {gameState === 'loading' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center z-50 bg-black">
          <Loader2 className="w-12 h-12 text-cyan-500 animate-spin mb-4" />
          <h2 className="text-white text-xl font-bold">Initializing Systems...</h2>
          <p className="text-gray-500 mt-2">Please allow camera access.</p>
        </div>
      )}

      {gameState === 'start' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center z-40 bg-black/80 backdrop-blur-md">
          <h1 className="text-7xl font-black text-transparent bg-clip-text bg-gradient-to-r from-red-500 via-white to-cyan-500 italic tracking-tighter mb-8 drop-shadow-[0_0_15px_rgba(255,255,255,0.5)]">
            NEON BLADE
          </h1>

          <div className="bg-gray-900/90 border border-gray-700 p-8 rounded-2xl max-w-md text-center shadow-2xl">
            <div className="flex justify-center gap-8 mb-6">
                <div className="flex flex-col items-center">
                    <div className="w-8 h-8 rounded-full bg-red-500 shadow-[0_0_15px_#ef4444] mb-2"></div>
                    <span className="text-red-400 font-bold text-sm">LEFT HAND</span>
                </div>
                <div className="flex flex-col items-center">
                    <div className="w-8 h-8 rounded-full bg-cyan-500 shadow-[0_0_15px_#06b6d4] mb-2"></div>
                    <span className="text-cyan-400 font-bold text-sm">RIGHT HAND</span>
                </div>
            </div>

            <p className="text-gray-300 mb-8">
              Cubes are approaching! Slash <span className="text-red-500 font-bold">Red cubes</span> with your left hand and <span className="text-cyan-500 font-bold">Blue cubes</span> with your right.
            </p>

            <button 
              onClick={startGame}
              className="w-full py-4 bg-white hover:bg-gray-200 text-black font-black text-xl rounded-full transition-all hover:scale-105 active:scale-95 flex items-center justify-center gap-2"
            >
              <Play className="fill-black" /> START GAME
            </button>
          </div>
        </div>
      )}

      {gameState === 'playing' && (
        <div className="absolute top-0 left-0 w-full p-8 flex justify-between items-start pointer-events-none z-30">
          <div>
            <div className="text-6xl font-black text-white italic drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">
              {score.toLocaleString()}
            </div>
            <div className="text-cyan-400 font-bold tracking-widest text-lg">SCORE</div>
          </div>

          <div className="flex flex-col items-center">
             <div className="text-4xl font-bold text-yellow-400 italic mb-1">
                x{combo}
             </div>
             <div className="text-yellow-600/80 text-xs font-bold tracking-widest">COMBO</div>
          </div>

          <div className="w-48 text-right">
            <div className="w-full h-4 bg-gray-800 rounded-full overflow-hidden border border-gray-700">
                <div 
                    className={`h-full transition-all duration-300 ${health > 50 ? 'bg-green-500' : 'bg-red-500'}`} 
                    style={{ width: `${health}%` }}
                />
            </div>
            <div className="text-gray-400 font-bold mt-1 text-sm">INTEGRITY</div>
          </div>
        </div>
      )}

      {gameState === 'gameover' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center z-50 bg-black/90 animate-in fade-in zoom-in duration-300">
          <ShieldAlert className="w-20 h-20 text-red-500 mb-6" />
          <h2 className="text-6xl font-black text-white mb-2 tracking-tight">SYSTEM FAILURE</h2>
          <div className="flex items-end gap-2 mb-8">
            <span className="text-gray-400 text-xl mb-1">FINAL SCORE:</span>
            <span className="text-4xl font-bold text-white">{score.toLocaleString()}</span>
          </div>

          <button 
            onClick={startGame}
            className="px-8 py-4 bg-red-600 hover:bg-red-500 text-white font-bold rounded-full text-xl transition-all hover:shadow-[0_0_20px_#dc2626] flex items-center gap-2"
          >
            <RotateCcw /> RETRY MISSION
          </button>
        </div>
      )}

      {/* Mobile/Tablet Warning */}
      <div className="absolute bottom-4 left-0 w-full text-center pointer-events-none opacity-50">
        <span className="text-xs text-gray-500 uppercase tracking-widest flex items-center justify-center gap-2">
            <Volume2 className="w-3 h-3" /> Audio Enabled • Stand back 2 meters
        </span>
      </div>
    </div>
  );
};

export default RhythmGame;

import React, { useEffect, useRef, useState } from 'react';
import { HandLandmarker } from '@mediapipe/tasks-vision';
import { createHandLandmarker } from '../utils/handDetection';
import { Loader2, Zap, Play, RotateCcw, Volume2, ShieldAlert } from 'lucide-react';

// --- Types ---

interface Point {
  x: number;
  y: number;
}

interface Cube {
  id: number;
  laneX: number; // -1 (left) to 1 (right)
  laneY: number; // -1 (up) to 1 (down)
  z: number;     // Depth: starts high, moves to 0
  color: 'red' | 'blue';
  hit: boolean;
}

interface Particle {
  id: number;
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

// --- Game Constants ---
const Z_START = 1000;
const Z_HIT = 100; // The "plane" where player slices
const SPEED = 15;
const FOCAL_LENGTH = 600;

// Colors
const COLOR_RED = '#ff0055'; // Left Hand
const COLOR_BLUE = '#00aaff'; // Right Hand

const RhythmGame: React.FC = () => {
  // UI State
  const [gameState, setGameState] = useState<'loading' | 'start' | 'playing' | 'gameover'>('loading');
  const [score, setScore] = useState(0);
  const [combo, setCombo] = useState(0);
  const [health, setHealth] = useState(100);

  // Refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const requestRef = useRef<number>();
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);

  // Game Logic Refs (Mutable)
  const cubesRef = useRef<Cube[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const frameCountRef = useRef(0);
  const handTrailsRef = useRef<{ left: Point[], right: Point[] }>({ left: [], right: [] });
  const gameStateRef = useRef(gameState);

  // Sync ref
  useEffect(() => {
    gameStateRef.current = gameState;
  }, [gameState]);

  // 1. Initialize System
  useEffect(() => {
    const init = async () => {
      try {
        landmarkerRef.current = await createHandLandmarker();
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { width: 1280, height: 720, facingMode: "user" } 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.addEventListener('loadeddata', () => setGameState('start'));
        }
      } catch (err) {
        console.error(err);
      }
    };
    init();

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (audioCtxRef.current) audioCtxRef.current.close();
    };
  }, []);

  // 2. Audio Engine (Synthesizer)
  // We synthesize a beat so we don't need external assets
  const playSound = (type: 'kick' | 'snare' | 'hihat' | 'miss' | 'hit') => {
    if (!audioCtxRef.current) return;
    const ctx = audioCtxRef.current;
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    if (type === 'hit') {
      osc.type = 'sine';
      osc.frequency.setValueAtTime(800, t);
      osc.frequency.exponentialRampToValueAtTime(0.01, t + 0.1);
      gain.gain.setValueAtTime(0.3, t);
      gain.gain.exponentialRampToValueAtTime(0.01, t + 0.1);
      osc.start(t);
      osc.stop(t + 0.1);
    } else if (type === 'kick') {
      osc.frequency.setValueAtTime(150, t);
      osc.frequency.exponentialRampToValueAtTime(0.01, t + 0.5);
      gain.gain.setValueAtTime(0.8, t);
      gain.gain.exponentialRampToValueAtTime(0.01, t + 0.5);
      osc.start(t);
      osc.stop(t + 0.5);
    } else if (type === 'snare') {
      osc.type = 'triangle';
      gain.gain.setValueAtTime(0.5, t);
      gain.gain.exponentialRampToValueAtTime(0.01, t + 0.2);
      osc.start(t);
      osc.stop(t + 0.2);
    } else if (type === 'miss') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(100, t);
      osc.frequency.linearRampToValueAtTime(50, t + 0.3);
      gain.gain.setValueAtTime(0.5, t);
      gain.gain.linearRampToValueAtTime(0.01, t + 0.3);
      osc.start(t);
      osc.stop(t + 0.3);
    }
  };

  // 3. Helper: 3D to 2D Projection
  const project = (x: number, y: number, z: number, width: number, height: number) => {
    // Standard perspective projection
    const scale = FOCAL_LENGTH / (FOCAL_LENGTH + z);
    const x2d = (x * width) * scale + (width / 2);
    const y2d = (y * height) * scale + (height / 2);
    return { x: x2d, y: y2d, scale };
  };

  const spawnCube = () => {
    // Random position in 2x2 grid
    // lanes: -0.5 (left/up) and 0.5 (right/down) give nice spacing
    const laneX = Math.random() > 0.5 ? 0.3 : -0.3;
    const laneY = Math.random() > 0.5 ? 0.2 : -0.2;

    // Color often matches side (Left=Red, Right=Blue) but sometimes crosses
    let color: 'red' | 'blue' = laneX < 0 ? 'red' : 'blue';
    if (Math.random() < 0.2) color = color === 'red' ? 'blue' : 'red'; // 20% crossover

    cubesRef.current.push({
      id: Date.now() + Math.random(),
      laneX,
      laneY,
      z: Z_START,
      color,
      hit: false
    });
  };

  const createParticles = (x: number, y: number, color: string) => {
    for (let i = 0; i < 10; i++) {
      particlesRef.current.push({
        id: Math.random(),
        x, y,
        vx: (Math.random() - 0.5) * 20,
        vy: (Math.random() - 0.5) * 20,
        life: 1.0,
        color,
        size: Math.random() * 10 + 5
      });
    }
  };

  // 4. Game Loop
  const loop = () => {
    if (gameStateRef.current !== 'playing' && gameStateRef.current !== 'gameover') return;

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    const video = videoRef.current;
    const landmarker = landmarkerRef.current;

    if (!canvas || !ctx || !video || !landmarker) return;

    // A. Hand Tracking
    let leftHand: Point | null = null;
    let rightHand: Point | null = null;

    if (video.readyState >= 2) {
      const results = landmarker.detectForVideo(video, performance.now());

      // Process Hands
      if (results.landmarks) {
        results.landmarks.forEach((landmarks, index) => {
          // Safety Check: handedness might be undefined or empty
          const handednessList = results.handedness?.[index];
          if (!handednessList || handednessList.length === 0) return;

          const handedness = handednessList[0]; // "Left" or "Right"
          const indexTip = landmarks[8];

          // Map Coordinates (Mirror X)
          const x = (1 - indexTip.x) * canvas.width;
          const y = indexTip.y * canvas.height;

          // MediaPipe "Left" is the person's Left Hand (which appears on Left side if mirrored)
          // We assign RED to Left Hand, BLUE to Right Hand
          if (handedness.categoryName === 'Left') {
            rightHand = { x, y }; // In selfie mode, "Left" handedness is the user's left hand
          } else {
            leftHand = { x, y };
          }
        });
      }
    }

    // Update Trails
    if (leftHand) {
      handTrailsRef.current.left.push(leftHand);
      if (handTrailsRef.current.left.length > 10) handTrailsRef.current.left.shift();
    }
    if (rightHand) {
      handTrailsRef.current.right.push(rightHand);
      if (handTrailsRef.current.right.length > 10) handTrailsRef.current.right.shift();
    }

    // B. Clear & Draw Background
    ctx.fillStyle = '#111';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Draw Video (Faint)
    ctx.save();
    ctx.globalAlpha = 0.2;
    ctx.translate(canvas.width, 0);
    ctx.scale(-1, 1);
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    ctx.restore();

    // Draw Perspective Grid (The "Tunnel")
    ctx.strokeStyle = '#333';
    ctx.lineWidth = 2;
    ctx.beginPath();
    // Floor lines
    for (let i = -2; i <= 2; i++) {
        const start = project(i * 0.5, 0.5, 0, canvas.width, canvas.height);
        const end = project(i * 2, 0.5, Z_START, canvas.width, canvas.height);
        ctx.moveTo(start.x, start.y);
        ctx.lineTo(end.x, end.y);
    }
    ctx.stroke();

    if (gameStateRef.current === 'gameover') {
      return; // Stop updating physics
    }

    // C. Music Sequencing (Simple Beat)
    frameCountRef.current++;
    // 120 BPM approx at 60fps = beat every 30 frames
    if (frameCountRef.current % 30 === 0) {
      spawnCube();
      // Simple Rhythm Pattern: Kick, Hat, Snare, Hat
      const beat = (frameCountRef.current / 30) % 4;
      if (beat === 0) playSound('kick');
      else if (beat === 2) playSound('snare');
      else playSound('kick'); // Constant drive
    }

    // D. Update & Draw Cubes
    for (let i = cubesRef.current.length - 1; i >= 0; i--) {
      const cube = cubesRef.current[i];
      cube.z -= SPEED;

      // Projection
      const proj = project(cube.laneX, cube.laneY, cube.z, canvas.width, canvas.height);
      const size = 60 * proj.scale; // Base size * perspective scale

      // Draw Cube
      ctx.fillStyle = cube.color === 'red' ? COLOR_RED : COLOR_BLUE;
      ctx.globalAlpha = Math.min(1, 1000 / cube.z); // Fade in

      // Draw a glowing box
      ctx.shadowBlur = 20;
      ctx.shadowColor = cube.color === 'red' ? COLOR_RED : COLOR_BLUE;
      ctx.fillRect(proj.x - size/2, proj.y - size/2, size, size);

      // Inner white box (the "arrow" placeholder)
      ctx.fillStyle = 'white';
      ctx.fillRect(proj.x - size/4, proj.y - size/4, size/2, size/2);

      ctx.shadowBlur = 0;
      ctx.globalAlpha = 1.0;

      // Collision Detection
      // We check if cube is near the "Hit Plane" (Z ~= 0 to 200)
      if (!cube.hit && cube.z < 200 && cube.z > -50) {
        const targetHand = cube.color === 'red' ? handTrailsRef.current.left : handTrailsRef.current.right;

        // Check if the specific hand is close to the projected cube center
        if (targetHand.length > 0) {
          const handPos = targetHand[targetHand.length - 1]; // Latest position
          const dx = handPos.x - proj.x;
          const dy = handPos.y - proj.y;
          const dist = Math.sqrt(dx*dx + dy*dy);

          // Hit!
          if (dist < size * 1.5) { // Forgiving hit box
            cube.hit = true;
            playSound('hit');
            createParticles(proj.x, proj.y, cube.color === 'red' ? COLOR_RED : COLOR_BLUE);
            setScore(prev => prev + 100);
            setCombo(prev => prev + 1);
            cubesRef.current.splice(i, 1);
            continue;
          }
        }
      }

      // Miss Logic (Passed the camera)
      if (cube.z < -200) {
        if (!cube.hit) {
            playSound('miss');
            setCombo(0);
            setHealth(prev => {
                const newHealth = prev - 10;
                if (newHealth <= 0) handleGameOver();
                return newHealth;
            });
        }
        cubesRef.current.splice(i, 1);
      }
    }

    // E. Draw Sabers (Trails)
    const drawTrail = (points: Point[], color: string) => {
      if (points.length < 2) return;
      ctx.beginPath();
      ctx.strokeStyle = color;
      ctx.lineWidth = 15;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.shadowBlur = 20;
      ctx.shadowColor = color;
      ctx.moveTo(points[0].x, points[0].y);
      for (let i = 1; i < points.length; i++) {
        ctx.lineTo(points[i].x, points[i].y);
      }
      ctx.stroke();
      ctx.shadowBlur = 0;
    };

    // Draw Left (Red) Hand - actually detected as Right by MP often due to mirroring, 
    // but we mapped MP Left -> Red earlier.
    if (handTrailsRef.current.left.length > 0) drawTrail(handTrailsRef.current.left, COLOR_RED);
    if (handTrailsRef.current.right.length > 0) drawTrail(handTrailsRef.current.right, COLOR_BLUE);


    // F. Draw Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
      const p = particlesRef.current[i];
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 0.05;
      if (p.life <= 0) {
        particlesRef.current.splice(i, 1);
      } else {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI*2);
        ctx.fill();
        ctx.globalAlpha = 1;
      }
    }

    requestRef.current = requestAnimationFrame(loop);
  };

  // 5. State Management
  const startGame = async () => {
    // Init Audio Context on user interaction (required by browsers)
    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioCtxRef.current?.state === 'suspended') {
      await audioCtxRef.current.resume();
    }

    setGameState('playing');
    setScore(0);
    setCombo(0);
    setHealth(100);

    cubesRef.current = [];
    particlesRef.current = [];
    handTrailsRef.current = { left: [], right: [] };
    frameCountRef.current = 0;

    if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
    }

    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    requestRef.current = requestAnimationFrame(loop);
  };

  const handleGameOver = () => {
    setGameState('gameover');
